const source = $node['Build Quora Prompt'].json;
const raw = String($json.text || '').trim();
function parseJson(text) {
  const fenced = text.match(/\`\`\`(?:json)?\s*([\s\S]*?)\`\`\`/i);
  const body = fenced ? fenced[1] : text;
  const first = body.indexOf('{');
  const last = body.lastIndexOf('}');
  if (first < 0 || last < first) throw new Error('Bonsai did not return JSON: ' + text.slice(0, 300));
  return JSON.parse(body.slice(first, last + 1));
}
const parsed = parseJson(raw);
const product = (source.products || []).find((p) => p.slug === parsed.selected_product_slug) || null;
return [{ json: { ...source, draftRaw: raw, safetyDecision: parsed.safety || 'human_review', affiliateAllowed: parsed.affiliate_allowed === true, selectedProductSlug: parsed.selected_product_slug || '', selectedProductName: product ? product.name : '', answerText: String(parsed.answer || '').trim(), draftReason: parsed.reason || '' } }];

